  drive_video_url:  body.drive_video_url || null,
  sheet_row:        body.sheet_row || null,
  callback_url:     body.callback_url || null,
  start_time:       Date.now()
}}];

const response = $input.first().json;
const data = $('Build Caption Prompt').first().json;

if (!response.candidates || !response.candidates[0] || !response.candidates[0].content) {
  console.warn('Gemini response empty — using fallback');
  const tags = data.hashtags || '#physics #science #education';
  const basic = data.title + '\n\n' + (data.description || data.topic) + '\n\n' + tags;
  return [{ json: { ...data, facebook_caption: basic, linkedin_caption: basic, generated_hashtags: tags } }];
}

let captions;
try {
  const raw = response.candidates[0].content.parts[0].text.trim();
  captions = JSON.parse(raw);
} catch(e) {
  console.warn('Caption JSON parse failed — using fallback');
  const tags = data.hashtags || '#physics #science #education';
  const basic = data.title + '\n\n' + (data.description || data.topic) + '\n\n' + tags;
  captions = { facebook_caption: basic, linkedin_caption: basic, hashtags: tags };
}

return [{ json: {
  ...data,
  facebook_caption:   captions.facebook_caption,
  linkedin_caption:   captions.linkedin_caption,
  instagram_caption:  captions.instagram_caption || captions.facebook_caption,
  tiktok_caption:     captions.tiktok_caption    || captions.youtube_caption,
  youtube_caption:    captions.youtube_caption   || captions.linkedin_caption,
  generated_hashtags: captions.hashtags
}}];

const { spawnSync } = require('child_process');
const fs = require('fs');
const data = $input.first().json;
const pageId = $env.FB_PAGE_ID;
const token = $env.FB_PAGE_ACCESS_TOKEN;

const ffmpegPath = data.final_video_path.replace('/data/ffmpeg', '/ffmpeg');
const title = (data.title || '').slice(0, 255);
const desc = ((data.facebook_caption || '') + '\n\n' + (data.generated_hashtags || data.hashtags || '')).slice(0, 5000);

console.log('FB Upload via curl: ' + ffmpegPath);

fs.writeFileSync('/tmp/fb_desc.txt', desc);
spawnSync('docker', ['cp', '/tmp/fb_desc.txt', 'qpc_ffmpeg_runner:/tmp/fb_desc.txt']);

const result = spawnSync('docker', [
  'exec', 'qpc_ffmpeg_runner',
  'curl', '-s', '--max-time', '300',
  '-X', 'POST',
  'https://graph-video.facebook.com/v18.0/' + pageId + '/videos',
  '-F', 'access_token=' + token,
  '-F', 'title=' + title,
  '-F', 'description=</tmp/fb_desc.txt',
  '-F', 'source=@' + ffmpegPath
], { timeout: 320000 });

if (result.error) throw new Error('curl spawn error: ' + result.error.message);
if (result.status !== 0) throw new Error('curl failed: ' + result.stderr.toString());

const output = result.stdout.toString().trim();
console.log('FB curl response: ' + output.slice(0, 200));

let parsed;
try { parsed = JSON.parse(output); }
catch(e) { throw new Error('FB response not JSON: ' + output.slice(0, 300)); }

if (parsed.error) return [{ json: { ...data, fb_status: 'FAILED', fb_error: JSON.stringify(parsed.error), fb_video_id: null, fb_post_url: null } }];
const videoId = parsed.id || parsed.video_id;
if (!videoId) return [{ json: { ...data, fb_status: 'FAILED', fb_error: 'No video ID: ' + output, fb_video_id: null, fb_post_url: null } }];
console.log('FB upload complete: ' + videoId);
return [{ json: { ...data, fb_status: 'SUCCESS', fb_video_id: videoId, fb_post_url: 'https://www.facebook.com/' + $env.FB_PAGE_ID + '/videos/' + videoId } }];

