const { spawnSync } = require('child_process');
const https = require('https');

const data = $input.first().json;

const clientId     = $env.YOUTUBE_OAUTH_CLIENT_ID;
const clientSecret = $env.YOUTUBE_OAUTH_CLIENT_SECRET;
const refreshToken = $env.YOUTUBE_REFRESH_TOKEN;

if (!clientId || !clientSecret || !refreshToken)
  throw new Error('Missing YouTube env vars — check YOUTUBE_OAUTH_CLIENT_ID / SECRET / REFRESH_TOKEN');

const tokenBody = [
  'grant_type=refresh_token',
  'client_id='     + encodeURIComponent(clientId),
  'client_secret=' + encodeURIComponent(clientSecret),
  'refresh_token=' + encodeURIComponent(refreshToken)
].join('&');

const tokenRes = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'oauth2.googleapis.com',
    path: '/token',
    method: 'POST',
    headers: {
      'Content-Type':  'application/x-www-form-urlencoded',
      'Content-Length': Buffer.byteLength(tokenBody)
    }
  }, res => {
    let body = '';
    res.on('data', c => body += c);
    res.on('end', () => resolve({ status: res.statusCode, body }));
  });
  req.on('error', reject);
  req.write(tokenBody);
  req.end();
});

const tokenData = JSON.parse(tokenRes.body);
if (!tokenData.access_token)
  throw new Error('YouTube token exchange failed: ' + tokenRes.body);
const accessToken = tokenData.access_token;

const title       = ((data.title || 'Physics Short') + ' #Shorts').slice(0, 100);
const ytCaption = (data.youtube_caption || data.linkedin_caption || data.facebook_caption || '').trim();
const ytTags    = (data.generated_hashtags || '').trim();
const description = (ytCaption + (ytTags ? ' ' + ytTags : '')).slice(0, 5000);

const metadata = JSON.stringify({
  snippet: {
    title,
    description,
    tags: ['physics', 'science', 'shorts', 'quantum', 'education'],
    categoryId: '28'
  },
  status: {
    privacyStatus: 'public',
    selfDeclaredMadeForKids: false
  }
});

const initRes = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'www.googleapis.com',
    path: '/upload/youtube/v3/videos?uploadType=resumable&part=snippet,status',
    method: 'POST',
    headers: {
      'Authorization':         'Bearer ' + accessToken,
      'Content-Type':          'application/json',
      'X-Upload-Content-Type': 'video/mp4',
      'Content-Length':        Buffer.byteLength(metadata)
    }
  }, res => {
    let body = '';
    res.on('data', c => body += c);
    res.on('end', () => resolve({ status: res.statusCode, headers: res.headers, body }));
  });
  req.on('error', reject);
  req.write(metadata);
  req.end();
});

const uploadUrl = initRes.headers['location'];
if (!uploadUrl)
  throw new Error('No YouTube upload URL. Status: ' + initRes.status + ' Body: ' + initRes.body.slice(-300));

const vidPath = (data.final_video_path || '').replace('/data/ffmpeg', '/ffmpeg');
if (!vidPath) throw new Error('No final_video_path in job data');

console.log('YT upload: ' + vidPath + ' → ' + uploadUrl.slice(0, 80) + '...');

const uploadResult = spawnSync('docker', [
  'exec', 'qpc_ffmpeg_runner',
  'curl', '-s',
  '--max-time', '600',
  '-X', 'PUT',
  uploadUrl,
  '-H', 'Content-Type: video/mp4',
  '--data-binary', '@' + vidPath
], { timeout: 620000, encoding: 'utf-8' });

const stdout = (uploadResult.stdout || '').trim();
let ytResponse;
try { ytResponse = JSON.parse(stdout); } catch(e) { ytResponse = {}; }

if (!ytResponse.id)
  throw new Error('YouTube upload failed: ' + stdout.slice(-500));

console.log('YT upload OK — video ID: ' + ytResponse.id);

return [{ json: {
  ...data,
  yt_video_id:  ytResponse.id,
  yt_video_url: 'https://www.youtube.com/shorts/' + ytResponse.id,
  yt_status:    'SUCCESS'
}}];

const res  = $input.first().json;
console.log('TikTok status: ' + res.tk_status + ' publish_id: ' + res.tk_publish_id);
return [{ json: { ...res } }];
